INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1016, 186431, 6, 654, '爱情の距离&#183;&#183;&#183;&#183;', '今天下雨了，我的心情不好有些伤感&#183;&#183;&#183;&#183;看着外面的雨一直在下着正如我的心一样~！！！我很想哭，可是我却没有泪水~~~最近的你去为你的梦想而开取你的另一个旅程。而我还是和以前一样没有变。虽然你一有时间就马上来陪我，我很开心但是我开心的同时心里不免有些伤感。看见你我有好多话想和你说，但是一见到你好象什么话都说不出口，现在的我总是你问你在“那里”感觉怎么样或遇到了什么？？剩下的也就沉默，我总是不停的重复着那句我好想你~！其实我真的很想你，无论在什么时候我都一直在想你~！~！！！虽然每天我们都为了见对方一面而争取时间，但是我始终害怕我们的距离会拉远&#183;&#183;&#183;&#183;&#183;也许我多心了也许是我无理取闹~~~！！！！睿，我只想告诉你无论发生什么事情我都不会放弃，现在的我不会在像以前一样让你担心害怕~~~~！！！！！我会一直陪你走到最后，虽然我不知道结果会不会是我们想的那样美好幸福~~~！！！但是我有勇气也信心可是陪你一直到永远~！！！我爱你~！请你记得我永远爱你~！', '今天下雨了，我的心情不好有些伤感····看着外面的雨一直在下着正如我的心一样~！！！我很想哭，可是我却没有泪水~~~最近的你去为你的梦想而开取你的另一个旅程。而我还是和以前一样没有变。虽然你一有时间就马上来陪我，我很开心但是我开心的同时心里不免有些伤感。看见你我有好多话想和你说，但是一见到你好象什么话都说不出口，现在的我总是你问你在“那里”感觉怎么样或遇到了什么？？剩下的也就沉默，我总是不停的重复着那句我好想你~！其实我真的很想你，无论在什么时候我都一直在想你~！~！！！虽然每天我们都为了见对方一面而争取时间，但是我始终害怕我们的距离会拉远·····也许我多心了也许是我无理取闹~~~！！！！睿，我只想告诉你无论发生什么事情我都不会放弃，现在的我不会在像以前一样让你担心害怕~~~~！！！！！我会一直陪你走到最后，虽然我不知道结果会不会是我们想的那样美好幸福~~~！！！但是我有勇气也信心可是陪你一直到永远~！！！我爱你~！请你记得我永远爱你~！', '冷雅爱火山，火山爱冷雅 ~

